import json
import os

tmp_file = '/tmp/config_items.txt'

with open('/Users/liuyi/xiaodazi/zenflux_agent/data/instances/xiaodazi/storage/uploads/20260210/965f53ea_triple_poison.json', 'r') as f:
    data = json.load(f)

def extract_paths(obj, path=None):
    if path is None:
        path = []

    if isinstance(obj, dict):
        for k, v in obj.items():
            yield from extract_paths(v, path + [str(k)])
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            yield from extract_paths(v, path + [str(i)])
    else:
        yield ('.'.join(path), obj)

with open(tmp_file, 'w') as out:
    count = 0
    for path_str, value in extract_paths(data):
        # 使用 json.dumps 安全序列化值
        value_str = json.dumps(value, ensure_ascii=False)
        out.write(f'{path_str}: {value_str}\n')
        count += 1
    out.write(f'\n总配置项数: {count}\n')

print(f'结果已写入 {tmp_file}，共 {count} 项')

